import { CommonModule } from "@angular/common";
import { Component, OnInit, inject } from "@angular/core";
import { FormsModule } from "@angular/forms";
import { RouterLink } from "@angular/router";
import { forkJoin } from "rxjs";
import { LecturerService } from "../../services/lecturer.service";

@Component({
  selector: "app-lecturer-dashboard",
  standalone: true,
  imports: [CommonModule, RouterLink, FormsModule],
  templateUrl: "./lecturer-dashboard.component.html",
  styleUrl: "./lecturer-dashboard.component.css"
})
export class LecturerDashboardComponent implements OnInit {
  private readonly lecturerService = inject(LecturerService);

  dashboard: any = null;
  courses: any[] = [];
  loading = true;
  errorMessage = "";
  courseSearch = "";
  readonly weekDays = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];
  monthLabel = "";
  monthGrid: Array<Array<number | null>> = [];
  private viewingDate = new Date();

  ngOnInit(): void {
    this.buildCalendar();
    forkJoin({
      dashboard: this.lecturerService.dashboard(),
      courses: this.lecturerService.courses()
    }).subscribe({
      next: ({ dashboard, courses }) => {
        this.dashboard = dashboard;
        this.courses = courses;
        this.loading = false;
      },
      error: (error) => {
        this.errorMessage = error?.error?.message ?? "Failed to load lecturer dashboard";
        this.loading = false;
      }
    });
  }

  previousMonth(): void {
    this.viewingDate = new Date(this.viewingDate.getFullYear(), this.viewingDate.getMonth() - 1, 1);
    this.buildCalendar();
  }

  nextMonth(): void {
    this.viewingDate = new Date(this.viewingDate.getFullYear(), this.viewingDate.getMonth() + 1, 1);
    this.buildCalendar();
  }

  isToday(day: number | null): boolean {
    if (!day) {
      return false;
    }
    const today = new Date();
    return (
      day === today.getDate() &&
      this.viewingDate.getMonth() === today.getMonth() &&
      this.viewingDate.getFullYear() === today.getFullYear()
    );
  }

  entriesForDay(day: number | null): any[] {
    if (!day || !this.dashboard?.recentActivity) {
      return [];
    }
    const dateKey = this.dateForCell(day);
    return this.dashboard.recentActivity
      .filter((entry: any) => this.toDateKey(entry.submittedAt) === dateKey)
      .slice(0, 3);
  }

  timelineEntries(): any[] {
    if (!this.dashboard?.recentActivity) {
      return [];
    }
    return this.dashboard.recentActivity.slice(0, 8);
  }

  filteredCourses(): any[] {
    const keyword = this.courseSearch.trim().toLowerCase();
    return [...this.courses]
      .filter((course) => !keyword || String(course.title ?? "").toLowerCase().includes(keyword))
      .sort((a, b) => String(a.title ?? "").localeCompare(String(b.title ?? "")));
  }

  courseImage(course: any, index: number): string {
    const title = String(course?.title ?? "").toLowerCase();
    if (title.includes("data")) {
      return "https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&w=1400&q=80";
    }
    if (title.includes("web")) {
      return "https://images.unsplash.com/photo-1504384308090-c894fdcc538d?auto=format&fit=crop&w=1400&q=80";
    }
    if (title.includes("database")) {
      return "https://images.unsplash.com/photo-1484417894907-623942c8ee29?auto=format&fit=crop&w=1400&q=80";
    }
    const fallback = [
      "https://images.unsplash.com/photo-1522202176988-66273c2fd55f?auto=format&fit=crop&w=1200&q=80",
      "https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?auto=format&fit=crop&w=1200&q=80",
      "https://images.unsplash.com/photo-1509062522246-3755977927d7?auto=format&fit=crop&w=1200&q=80"
    ];
    return fallback[index % fallback.length];
  }

  recentSubmissionCount(courseTitle: string): number {
    if (!this.dashboard?.recentActivity) {
      return 0;
    }
    return this.dashboard.recentActivity.filter((item: any) => item.courseTitle === courseTitle).length;
  }

  private buildCalendar(): void {
    this.monthLabel = new Intl.DateTimeFormat("en-US", {
      month: "long",
      year: "numeric"
    }).format(this.viewingDate);

    const year = this.viewingDate.getFullYear();
    const month = this.viewingDate.getMonth();
    const firstDate = new Date(year, month, 1);
    const totalDays = new Date(year, month + 1, 0).getDate();

    let firstWeekDay = firstDate.getDay();
    firstWeekDay = firstWeekDay === 0 ? 7 : firstWeekDay;

    const rows: Array<Array<number | null>> = [];
    let week: Array<number | null> = new Array(firstWeekDay - 1).fill(null);

    for (let day = 1; day <= totalDays; day++) {
      week.push(day);
      if (week.length === 7) {
        rows.push(week);
        week = [];
      }
    }

    if (week.length > 0) {
      while (week.length < 7) {
        week.push(null);
      }
      rows.push(week);
    }

    this.monthGrid = rows;
  }

  private dateForCell(day: number): string {
    const year = this.viewingDate.getFullYear();
    const month = String(this.viewingDate.getMonth() + 1).padStart(2, "0");
    const dayValue = String(day).padStart(2, "0");
    return `${year}-${month}-${dayValue}`;
  }

  private toDateKey(value: string): string {
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) {
      return "";
    }
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, "0");
    const day = String(date.getDate()).padStart(2, "0");
    return `${year}-${month}-${day}`;
  }
}
<div class="container lecturer-shell">
  @if (loading) {
    <p>Loading dashboard...</p>
  } @else if (errorMessage) {
    <p class="error">{{ errorMessage }}</p>
  } @else if (dashboard) {
    <section class="panel lecturer-layout">
      <section class="main-panel">
        <section class="lecturer-hero">
          <div class="hero-overlay">
            <p class="hero-kicker">EduSIM Lecturer Portal</p>
            <h2>Guide Learning and Assessment from One Place</h2>
            <p>Manage course content, publish quizzes, and monitor student outcomes with a clear workflow.</p>
          </div>
        </section>

        <section class="welcome-band">
          <div>
            <p class="welcome-tag">Welcome back</p>
            <h1>{{ dashboard.lecturer.name }}</h1>
            <p class="muted">Pantau kursus, kuiz, dan prestasi pelajar dari satu tempat.</p>
          </div>
        </section>

        <section class="grid cards-3">
          <article class="panel card">
            <h2>{{ dashboard.stats.courses }}</h2>
            <p>Courses Managed</p>
          </article>
          <article class="panel card">
            <h2>{{ dashboard.stats.videos }}</h2>
            <p>Total Videos</p>
          </article>
          <article class="panel card">
            <h2>{{ dashboard.stats.quizzes }}</h2>
            <p>Total Quizzes</p>
          </article>
          <article class="panel card">
            <h2>{{ dashboard.stats.students }}</h2>
            <p>Enrolled Students</p>
          </article>
        </section>

        <section class="panel block course-overview-block">
          <div class="overview-head">
            <h2>Course Overview</h2>
            <span>{{ filteredCourses().length }} course(s)</span>
          </div>

          <div class="overview-search">
            <input
              type="text"
              name="lecturerCourseSearch"
              placeholder="Search managed course"
              [(ngModel)]="courseSearch">
          </div>

          @if (filteredCourses().length === 0) {
            <p class="muted">No managed courses found.</p>
          } @else {
            <div class="overview-grid">
              @for (course of filteredCourses(); track course.courseId; let i = $index) {
                <article class="overview-card">
                  <img [src]="courseImage(course, i)" [alt]="course.title">
                  <div class="overview-body">
                    <p class="overview-meta">Managed Course</p>
                    <h3>{{ course.title }}</h3>
                    <p class="overview-desc">{{ course.description || "Course description is not set yet." }}</p>
                    <div class="overview-stats">
                      <span>{{ course.videoCount }} videos</span>
                      <span>{{ course.quizCount }} quizzes</span>
                      <span>{{ recentSubmissionCount(course.title) }} submissions</span>
                    </div>
                    <div class="overview-actions">
                      <a
                        class="btn btn-outline"
                        [routerLink]="['/lecturer/manage']"
                        [queryParams]="{ courseId: course.courseId, flash: 'Course workspace opened.' }">
                        Open Course
                      </a>
                      <a
                        class="btn btn-outline"
                        [routerLink]="['/lecturer/quiz-settings']"
                        [queryParams]="{ courseId: course.courseId, mode: 'create' }">
                        Add/Edit Quiz
                      </a>
                      <a
                        class="btn btn-outline"
                        [routerLink]="['/lecturer/monitoring']"
                        [queryParams]="{ courseId: course.courseId, courseTitle: course.title }">
                        Performance Dashboard
                      </a>
                    </div>
                  </div>
                </article>
              }
            </div>
          }
        </section>

        <section class="panel block">
          <div class="heading">
            <h2>Recent Submission</h2>
          </div>
          @if (dashboard.recentActivity.length === 0) {
            <p class="muted">Tiada submission lagi.</p>
          } @else {
            <table>
              <thead>
                <tr>
                  <th>Student</th>
                  <th>Quiz</th>
                  <th>Course</th>
                  <th>Score</th>
                  <th>Status</th>
                  <th>Date</th>
                </tr>
              </thead>
              <tbody>
                @for (item of dashboard.recentActivity; track item.attemptId) {
                  <tr>
                    <td>{{ item.studentName }}</td>
                    <td>{{ item.quizTitle }}</td>
                    <td>{{ item.courseTitle }}</td>
                    <td>{{ item.score }}%</td>
                    <td>
                      <span class="badge" [class.fail]="!item.passed">
                        {{ item.passed ? "PASS" : "FAIL" }}
                      </span>
                    </td>
                    <td>{{ item.submittedAt | date: "medium" }}</td>
                  </tr>
                }
              </tbody>
            </table>
          }
        </section>
      </section>

      <aside class="side-panel">
        <section class="calendar-card">
          <div class="month-head">
            <h3>{{ monthLabel }}</h3>
            <div class="month-nav">
              <button type="button" (click)="previousMonth()">&#8249;</button>
              <button type="button" (click)="nextMonth()">&#8250;</button>
            </div>
          </div>

          <div class="calendar-grid">
            @for (dayLabel of weekDays; track dayLabel) {
              <span class="weekday">{{ dayLabel }}</span>
            }
            @for (week of monthGrid; track $index) {
              @for (day of week; track $index) {
                <div class="day-cell" [class.today]="isToday(day)" [class.has-entry]="entriesForDay(day).length > 0">
                  {{ day ?? "" }}
                </div>
              }
            }
          </div>
        </section>

        <section class="timeline-card">
          <h3>Timeline</h3>
          @if (timelineEntries().length === 0) {
            <p class="muted">No activity yet.</p>
          } @else {
            <ul class="timeline-list">
              @for (item of timelineEntries(); track item.attemptId) {
                <li>
                  <p class="timeline-title">{{ item.quizTitle }}</p>
                  <p class="timeline-sub">{{ item.studentName }}</p>
                  <p class="timeline-meta">{{ item.submittedAt | date: "shortTime" }} - {{ item.score }}%</p>
                </li>
              }
            </ul>
          }
        </section>
      </aside>
    </section>
  }
</div>
